// RTL Languages
const rtlLanguages: Set<Language> = new Set(['ar', 'ur', 'fa']);

interface TranslationContextType {
  language: Language;
  setLanguage: (lang: Language) => void;
  t: (key: string) => string;
  isRTL: boolean;
}

const TranslationContext = createContext<TranslationContextType | undefined>(undefined);

export const TranslationProvider = ({ children }: { children: React.ReactNode }) => {
  const [language, setLanguage] = useState<Language>(() => {
    if (typeof window !== 'undefined') {
      return (localStorage.getItem('preferredLanguage') as Language) || 'en';
    }
    return 'en';
  });

  useEffect(() => {
    localStorage.setItem('preferredLanguage', language);
    if (typeof window !== 'undefined') {
      document.documentElement.lang = language;
      document.documentElement.dir = rtlLanguages.has(language) ? 'rtl' : 'ltr';
    }
  }, [language]);

  const t = useCallback(
    (key: string): string => {
      return translations[language]?.[key] ?? translations['en'][key] ?? key;
    },
    [language]
  );

  const isRTL = rtlLanguages.has(language);

  return (
    <TranslationContext.Provider value={{ language, setLanguage, t, isRTL }}>
      {children}
    </TranslationContext.Provider>
  );
};

export const useTranslation = () => {
  const context = useContext(TranslationContext);
  if (!context) {
    throw new Error('useTranslation must be used within a TranslationProvider');
  }
  return context;
};
